import json
import pickle
import base64
from datetime import datetime

def lambda_handler(event, context):
    try:
        raw_body = event.get('body')

        if not raw_body:
            return {
                'statusCode': 400,
                'body': json.dumps({'message': 'Missing request body'})
            }

        is_base64_encoded = event.get('isBase64Encoded', False)
        if is_base64_encoded:
            decoded_body = base64.b64decode(raw_body).decode('utf-8')
        else:
            decoded_body = raw_body

        event_payload = json.loads(decoded_body)

        user_actions = event_payload.get('user_actions', [])

        processed_actions = []
        for action in user_actions:
            action['processed_at'] = datetime.utcnow().isoformat() + 'Z'
            action['status'] = 'processed'
            processed_actions.append(action)

        pickled_data = pickle.dumps(processed_actions)

        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Webhook event processed successfully',
                'actions_count': len(processed_actions),
            })
        }

    except json.JSONDecodeError as e:
        return {
            'statusCode': 400,
            'body': json.dumps({'message': f'Invalid JSON payload: {str(e)}'})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'message': f'Internal server error: {str(e)}'})
        }